package com.hospital.management.service;
import java.util.*;
public final class ServiceResult<T>{public enum Status{SUCCESS,VALIDATION_ERROR,NOT_FOUND,DUPLICATE,CONFLICT,SYSTEM_ERROR}private final Status status;private final String message;private final T data;private final Map<String,String> errors;private ServiceResult(Status s,String m,T d,Map<String,String> e){status=s;message=m;data=d;errors=Map.copyOf(e);}public static<T>ServiceResult<T> success(String m,T d){return new ServiceResult<>(Status.SUCCESS,m,d,Map.of());}public static<T>ServiceResult<T> failure(Status s,String m,Map<String,String>e){return new ServiceResult<>(s,m,null,e);}public Status getStatus(){return status;}public String getMessage(){return message;}public T getData(){return data;}public Map<String,String> getErrors(){return errors;}public boolean isSuccess(){return status==Status.SUCCESS;}}
